// מפענח את ה-JSON מ-Groq ומכין שאילתת תמונות ל-Openverse.
const content = $json.choices[0].message.content;
let ai;
try { ai = JSON.parse(content); }
catch (e) { ai = JSON.parse(content.replace(/```json|```/g, '').trim()); }
return [{ json: { ai, query: (ai.city || '') + ' landmark city' } }];

// בונה את דף ה-HTML המעוצב (גלריה + כרטיסי אטרקציות + מפת Leaflet עם סמנים).
// >>> ערכו את שתי השורות הבאות לפי המשתמש/ריפו שלכם <<<
const OWNER = 'hila24';
const REPO  = 'AfekaRot';

const ai = $('Parse + Image Query').first().json.ai;
const ov = $json;
const images = (ov.results || []).map(r => r.url).filter(Boolean).slice(0, 3);

function esc(s){return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
const city=esc(ai.city), country=esc(ai.country), intro=esc(ai.intro);
const atts = Array.isArray(ai.attractions)?ai.attractions:[];
const pts = atts.filter(a=>typeof a.lat==='number'&&typeof a.lng==='number');
const cLat = pts.length?pts.reduce((s,a)=>s+a.lat,0)/pts.length:32.0853;
const cLng = pts.length?pts.reduce((s,a)=>s+a.lng,0)/pts.length:34.7818;
const gallery = images.map((u,i)=>`      <img src="${esc(u)}" alt="${city} ${i+1}" loading="lazy">`).join('\n');
const cards = atts.map((a,i)=>`\n      <article class="card"><span class="num">${i+1}</span><h3>${esc(a.name)}</h3><p>${esc(a.description)}</p><small>\uD83D\uDCCD ${Number(a.lat).toFixed(4)}, ${Number(a.lng).toFixed(4)}</small></article>`).join('');
const markers = JSON.stringify(atts.map(a=>({name:a.name,lat:a.lat,lng:a.lng})));

const html = `<!DOCTYPE html>
<html lang="he" dir="rtl"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>${city} — מדריך אטרקציות</title>
<link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css">
<style>:root{--bg:#0f172a;--card:#1e293b;--accent:#38bdf8;--text:#e2e8f0}*{box-sizing:border-box}body{margin:0;font-family:Segoe UI,Arial,sans-serif;background:var(--bg);color:var(--text)}header{padding:48px 20px;text-align:center;background:linear-gradient(135deg,#0ea5e9,#6366f1);color:#fff}header h1{margin:0;font-size:2.6rem}header p{max-width:760px;margin:16px auto 0;line-height:1.7;opacity:.95}.wrap{max-width:1000px;margin:0 auto;padding:24px 20px 60px}h2{color:var(--accent);border-bottom:2px solid #334155;padding-bottom:8px}.gallery{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:12px}.gallery img{width:100%;height:200px;object-fit:cover;border-radius:12px}.cards{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:16px}.card{background:var(--card);border-radius:14px;padding:18px;position:relative}.card .num{position:absolute;inset-inline-start:14px;top:-14px;width:30px;height:30px;background:var(--accent);color:#04293a;border-radius:50%;display:grid;place-items:center;font-weight:700}.card h3{margin:6px 0 8px}#map{height:420px;border-radius:14px;margin-top:8px}footer{text-align:center;padding:24px;opacity:.6;font-size:.85rem}</style></head>
<body><header><h1>${city}${country?(' · '+country):''}</h1><p>${intro}</p></header>
<div class="wrap"><h2>תמונות מהאזור</h2><div class="gallery">\n${gallery}\n</div>
<h2>אטרקציות מומלצות</h2><div class="cards">${cards}\n</div>
<h2>מפה ונקודות ציון</h2><div id="map"></div></div>
<footer>נוצר אוטומטית באמצעות n8n + Groq AI · מפה: OpenStreetMap</footer>
<script src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js"></script>
<script>const markers=${markers};const map=L.map('map').setView([${cLat},${cLng}],12);L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{attribution:'&copy; OpenStreetMap'}).addTo(map);const g=[];markers.forEach(m=>{if(typeof m.lat==='number'&&typeof m.lng==='number'){g.push(L.marker([m.lat,m.lng]).addTo(map).bindPopup(m.name));}});if(g.length)map.fitBounds(L.featureGroup(g).getBounds().pad(0.2));</script></body></html>`;

const slug = (ai.city||'page').toString().trim().toLowerCase().replace(/[^a-z0-9\u0590-\u05FF]+/g,'-').replace(/^-|-$/g,'') || 'page';
const filename = `${slug}-${Date.now()}.html`;
const filePath = `hw-3/generated/${filename}`;
const pageUrl = `https://${OWNER}.github.io/${REPO}/${filePath}`;

// HTML קצר לגוף המייל (תצוגה מקדימה + קישור לדף המלא עם המפה).
const emailHtml = `<div style="font-family:Arial;direction:rtl"><h2>${city}${country?(' · '+country):''}</h2><p>${intro}</p><p>${images.map(u=>`<img src="${u}" style="width:150px;height:100px;object-fit:cover;margin:4px;border-radius:8px">`).join('')}</p><p><b>אטרקציות:</b> ${atts.map(a=>esc(a.name)).join(' · ')}</p><p>🔗 הדף המלא (כולל מפה אינטראקטיבית): <a href="${pageUrl}">${pageUrl}</a></p></div>`;

return [{ json: { html, emailHtml, filePath, filename, pageUrl, city, owner: OWNER, repo: REPO } }];
